import React from "react"

export interface LinkInterface {
  href: string
  text: string
}

/**
 * Links used in the navigation component
 * @param props  <LinkInterface> Href and text string required
 */
const Link: React.FunctionComponent<LinkInterface> = props => {
  return (
    <a
      href={props.href}
      className="block mt-4 lg:inline-block lg:mt-0 text-black-200 hover:text-gray-600 mr-4"
    >
      {props.text}
    </a>
  )
}

export default Link
