import React, { useEffect, useState } from "react"

import Link, { LinkInterface } from "./link"

interface NavigationInterface {
  siteTitle: string
  pageTitle?: string | null
  links: Array<LinkInterface>
}

/**
 * Navigation component
 * @param props <NavigationInterface> Site title and array of links required
 */
const Navigation: React.FunctionComponent<NavigationInterface> = props => {
  const [menuIsVisible, setMenu] = useState(false)
  return (
    <nav className="flex items-center justify-between flex-wrap bg-white-500 py-6">
      <div className="flex items-center flex-shrink-0 text-black mr-6">
        <a href="/">
          <span className="font-semibold text-xl tracking-tight">
            {props.siteTitle} {props.pageTitle && `| ${props.pageTitle}`}
          </span>
        </a>
      </div>
      <div
        className="block lg:hidden"
        id="menu"
        onClick={() => setMenu(!menuIsVisible)}
      >
        <button className="flex items-center px-3 py-2 border rounded text-black-200 border-black-400 hover:text-gray-600 hover:border-gray-600">
          <svg
            className="fill-current h-3 w-3"
            viewBox="0 0 20 20"
            xmlns="http://www.w3.org/2000/svg"
          >
            <title>Menu</title>
            <path d="M0 3h20v2H0V3zm0 6h20v2H0V9zm0 6h20v2H0v-2z" />
          </svg>
        </button>
      </div>
      <div
        className="w-full block flex-grow lg:flex lg:items-center lg:w-auto"
        style={
          // TODO: Make less hacky
          !menuIsVisible && document.documentElement.clientWidth < 1024
            ? { display: "none" }
            : {}
        }
      >
        <div className="text-sm lg:flex-grow">
          {props.links.map(link => (
            <Link key={link.href} href={link.href} text={link.text} />
          ))}
        </div>
      </div>
    </nav>
  )
}

export default Navigation
